import pandas as pd
import numpy as np
import json
import pystan

# Load data
train_X = pd.read_csv('train_X.csv')
train_y = pd.read_csv('train_y.csv')
test_X = pd.read_csv('test_X.csv')
with open('meta_public.json', 'r') as f:
    meta = json.load(f)

N = train_X.shape[0]
D = train_X.shape[1]
P = meta['P']
jitter = meta['jitter']
N_new = test_X.shape[0]

# Convert to numpy arrays
X = train_X.values
y = train_y['y'].values
X_new = test_X.values

# Construct H and H_new as in R script: cbind(1, train_X[,1], train_X[,2])
H = np.column_stack((np.ones(N), X[:, 0], X[:, 1]))
if N_new > 0:
    H_new = np.column_stack((np.ones(N_new), X_new[:, 0], X_new[:, 1]))
else:
    H_new = np.zeros((0, P))

# Prepare data list
data_list = {
    'N': N,
    'D': D,
    'X': X,
    'P': P,
    'H': H,
    'y': y,
    'jitter': jitter,
    'N_new': N_new,
    'X_new': X_new if N_new > 0 else np.zeros((0, D)),
    'H_new': H_new
}

