  int<lower=1> N;
  int<lower=1> D;
  matrix[N, D] X;
  int<lower=1> P;
  matrix[N, P] H;
  vector[N] y;
  real<lower=0> jitter;

  int<lower=0> N_new;
  matrix[N_new, D] X_new;
  matrix[N_new, P] H_new;
}

parameters {
