        'max_treedepth': 14,
        'adapt_gamma': 0.05,
        'adapt_kappa': 0.75,
        'adapt_t0': 10,
        'adapt_init_buffer': 100,
        'adapt_term_buffer': 50,
        'adapt_window': 25
    }
)

# Extract posterior means
post = fit.extract()
alpha_post = np.mean(post['alpha'])
sigma_post = np.mean(post['sigma'])
rho_post = np.mean(post['rho'], axis=0)
beta_post = np.mean(post['beta'], axis=0)

print('Posterior means:')
print('alpha:', alpha_post)
print('sigma:', sigma_post)
print('rho:  ', rho_post)
print('beta: ', beta_post)

# Save to CSV files
np.savetxt('alpha_est.csv', [alpha_post], delimiter=',')
np.savetxt('sigma_est.csv', [sigma_post], delimiter=',')
np.savetxt('rho_est.csv', rho_post, delimiter=',')
np.savetxt('beta_est.csv', beta_post, delimiter=',')

print('Results saved.')
EOF
",
      "duration": 2.0
    }
